INSERT INTO `news` (`title`, `summary_60`, `summary_30`, `full_content`, `category_id`, `image`, `publish_date`, `read_count`) VALUES
('Global Climate Summit Reaches Historic Agreement on Emissions', 'Leaders from over 100 nations have agreed on a comprehensive plan to cut global carbon emissions by 40% over the next decade. The landmark agreement includes a $100 billion annual fund to assist developing nations in transitioning to renewable energy. Despite earlier disagreements, major economies compromised on timelines to finalize the deal.', 'Nations agreed to cut carbon emissions by 40% and establish a $100B climate fund for developing countries.', 'What Happened?\nThe 2026 Global Climate Summit concluded with a binding agreement among 140 countries to reduce international carbon output significantly by 2036.\n\nWhy It Matters?\nThis is the first time all major industrial nations have aligned on a strict, accountable timeline. It indicates a massive forthcoming shift in global energy markets and manufacturing policies.\n\nKey Facts\n- 40% reduction target for carbon emissions.\n- $100 billion annual green energy fund for developing nations.\n- Phased penalties for countries failing to meet intermediate targets.', 1, NULL, DATE_SUB(NOW(), INTERVAL 2 HOUR), 1432),

('Tech Giant Unveils Revolutionary Quantum Processor', 'A leading technology corporation has officially revealed its latest 1000-qubit quantum processor, claiming it achieves quantum advantage over traditional supercomputers for complex molecular simulations. The chip could drastically accelerate drug discovery and advanced material design, marking a new era in computational power.', 'A new 1000-qubit processor achieves quantum advantage, potentially accelerating new drug discoveries and material sciences.', 'What Happened?\nToday, researchers unveiled a 1000-qubit quantum processor capable of performing complex molecular simulations that would take classical supercomputers thousands of years to complete.\n\nWhy It Matters?\nQuantum advantage has long been a theoretical milestone. Moving into practical applications means we could see rapid advancements in medicine, battery technology, and cryptography within years rather than decades.\n\nKey Facts\n- 1000-qubit processing architecture.\n- Successful simulation of complex chemical reactions.\n- Commercial availability expected in late 2028.', 3, NULL, DATE_SUB(NOW(), INTERVAL 5 HOUR), 2890),

('Local Startup Secures Record Funding Round in Dhaka', 'A Dhaka-based fintech startup focused on micro-lending for rural farmers has secured a record-breaking $50 million Series B funding round. The investment was led by prominent international venture funds. The startup plans to expand its services to over 500,000 farmers across Bangladesh in the next two years.', 'A Dhaka fintech startup raised $50 million to expand micro-lending services to rural farmers across Bangladesh.', 'What Happened?\nAgriFin BD, a startup based in Dhaka, successfully closed a $50 million funding round. The capital will be used to expand its mobile-based lending platform.\n\nWhy It Matters?\nAccess to capital is a major barrier for agricultural growth in Bangladesh. By digitizing the lending process and using alternative credit scoring, more farmers can purchase modern equipment and high-yield seeds.\n\nKey Facts\n- $50 Million Series B funding.\n- Goal to reach 500,000 farmers in 2 years.\n- App provides instant credit scoring based on harvest data.', 2, NULL, DATE_SUB(NOW(), INTERVAL 1 DAY), 876),

('Major Merger Expected in the Electric Vehicle Market', 'Two of the world''s largest legacy automotive manufacturers have announced a strategic merger of their electric vehicle divisions. The combined entity is projected to have a valuation of over $80 billion and aims to challenge the current market leaders by pooling research and manufacturing resources.', 'Two major auto manufacturers are merging their EV divisions to form an $80 billion entity to dominate the market.', 'What Happened?\nA definitive agreement has been signed to merge the EV divisions of two legacy auto giants, creating a new standalone company focused exclusively on electric mobility.\n\nWhy It Matters?\nThis consolidation signals a rapid acceleration in the shift away from internal combustion engines. By pooling resources, the new company expects to lower battery costs by 20% and introduce a $25,000 consumer EV by next year.\n\nKey Facts\n- $80 Billion combined valuation.\n- Focus on affordable, mass-market electric vehicles.\n- Joint development of solid-state battery technology.', 4, NULL, DATE_SUB(NOW(), INTERVAL 2 DAY), 3102),

('National Cricket Team Wins Regional Championship Final', 'In a thrilling final match that went down to the final over, the national cricket team secured a dramatic 3-wicket victory over their regional rivals. The captain scored a magnificent unbeaten century to guide the team during a tense chase, securing the championship trophy in front of a sold-out home crowd.', 'The national cricket team won the regional championship with a tense 3-wicket victory, led by the captain''s century.', 'What Happened?\nThe national team chased down a target of 285 runs with just two balls to spare, winning the regional championship final in a spectacular fashion.\n\nWhy It Matters?\nThis victory brings the regional trophy back home after a 12-year drought. It also boosts the team''s ranking ahead of the upcoming World Cup qualifiers.\n\nKey Facts\n- Chased 285 runs successfully.\n- Captain scored 104 not out.\n- First championship win in 12 years.', 5, NULL, DATE_SUB(NOW(), INTERVAL 3 DAY), 4521),

('Award-Winning Director Announces Surprising Sci-Fi Epic', 'The critically acclaimed director known for historical dramas has surprised the entertainment industry by announcing a new big-budget sci-fi epic. Pre-production has already begun on the project, which will explore humanity''s first contact with extraterrestrial intelligence. A massive ensemble cast is reportedly in talks to join.', 'A renowned historical drama director announced a surprise pivot to a big-budget sci-fi epic about first alien contact.', 'What Happened?\nDuring a press conference in Los Angeles, the award-winning director revealed their next project: a $150 million sci-fi saga titled "Beyond the Horizon."\n\nWhy It Matters?\nThis represents a massive genre shift for the director, generating significant buzz in Hollywood. The film is expected to push the boundaries of visual effects and practical set design.\n\nKey Facts\n- Estimated budget: $150 Million.\n- Story focuses on diplomatic first contact.\n- Scheduled for a worldwide release in late 2027.', 6, NULL, DATE_SUB(NOW(), INTERVAL 4 DAY), 1980);
